class Playground {
    async run(inputs) {
        const rawInput = inputs[0] || "racecar";

        // Step 1: Clean the string (lowercase and remove non-alphanumeric)
        this.log("Cleaning string: removing non-alphanumeric characters and converting to lowercase.");
        const cleanedString = rawInput.toLowerCase().replace(/[^a-z0-9]/g, "");
        const chars = cleanedString.split("");

        // Step 2: Initialize Visuals
        await this.string_array.init(chars);
        await this.variables.init([]);

        if (chars.length === 0) {
            this.log("Empty string is technically a palindrome.");
            return true;
        }

        let left = 0;
        let right = chars.length - 1;

        // Step 3: Two-Pointer Iteration
        while (left <= right) {
            // Update Visual State
            this.variables.put("left_idx", left);
            this.variables.put("right_idx", right);
            this.variables.put("left_char", chars[left]);
            this.variables.put("right_char", chars[right]);

            // Highlight pointers in blue
            this.string_array.highlight(left, "#00e0ff");
            this.string_array.highlight(right, "#00e0ff");

            this.log(`Comparing characters at indices ${left} and ${right}`);
            await this.await();

            if (chars[left] !== chars[right]) {
                // Highlight mismatch in red
                this.string_array.highlight(left, "#ff4d4d");
                this.string_array.highlight(right, "#ff4d4d");
                this.log(`Mismatch found: '${chars[left]}' !== '${chars[right]}'. Not a palindrome.`);
                await this.await();
                return false;
            }

            // Highlight match in green
            this.string_array.highlight(left, "#00f5a0");
            this.string_array.highlight(right, "#00f5a0");
            this.log(`Characters match: '${chars[left]}'. Moving pointers.`);
            await this.await();

            left++;
            right--;
        }

        this.log("All pointers met or crossed with successful matches. This is a palindrome!");
        return true;
    }
}
